mongodb:createCollection.mongodb:options:
{
    validator: {
        $jsonSchema: {
            bsonType: "object",
            required: [
                "id",
                "slideShowId",
                "version",
                "createdDate",
                "createdUser",
                "centerPoint",
                "slides"
            ],
            properties: {
                id: {
                    bsonType: "string",
                },
                slideShowId: {
                    bsonType: "string",
                },
                centerPoint: {
                    "bsonType": "array",
                    "items": {
                        "bsonType": "double"
                    }
                },
                mapZoom: {
                    bsonType: "int",
                },
                title: {
                    bsonType: "string",
                },
                description: {
                    bsonType: "string",
                },
                version: {
                    bsonType: "string",
                },
                nextVersion: {
                    bsonType: "string",
                },
                prevVersion: {
                    bsonType: "string",
                },
                createdDate: {
                    bsonType: "string",
                },
                createdUser: {
                    bsonType: "string",
                },
                lastModifiedDate: {
                    bsonType: "string",
                },
                lastModifiedUser: {
                    bsonType: "string",
                },
                hash: {
                    bsonType: "string",
                },
                slides:{
                    bsonType: "array",
                    items:{
                         required: ["slideId", "polygons"],
                         properties: {
                            slideId: {
                                bsonType: "string",
                            },
                            polygons: {
                                bsonType: "array",
                                items: {
                                    required: [
                                        "id",
                                        "polygonId",
                                        "coordinates"
                                    ],
                                    properties: {
                                        id: {
                                            bsonType: "string",
                                        },
                                        polygonId: {
                                            bsonType: "string",
                                        },
                                        color: {
                                            bsonType: "int",
                                        }
                                        coordinates: {
                                            "bsonType": "array",
                                            "items": {
                                                "bsonType": "array",
                                                "items": {
                                                    "bsonType": "double"
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                         }
                    }
                }
            }
        }
    },
    validationAction: "error",
    validationLevel: "strict"
}
